def jump(nums: List[int]) -> int:
    def dfs(position: int) -> int:
        if position >= len(nums) - 1:
            return 0
        if nums[position] == 0:
            return float('inf')

        min_jumps = float('inf')
        for jump in range(1, nums[position] + 1):
            next_position = position + jump
            min_jumps = min(min_jumps, 1 + dfs(next_position))

        return min_jumps

    result = dfs(0)
    return result if result != float('inf') else 0

