        int n = nums.size();
        if (position >= n - 1) {
            return 0;
        }

        int minJumps = INT_MAX;
        for (int i = 1; i <= nums[position]; ++i) {
            if (position + i < n) {
                int jumps = jumpHelper(nums, position + i);
                if (jumps != INT_MAX) {
                    minJumps = min(minJumps, jumps + 1);
                }
            }
        }

        return minJumps;
    }
