package main

import "fmt"

func jump(nums []int) int {
	return jumpRecursive(nums, 0)
}

func jumpRecursive(nums []int, position int) int {
	if position >= len(nums)-1 {
		return 0
	}

	minJumps := int(^uint(0) >> 1) // Initialize to max int
	for i := 1; i <= nums[position]; i++ {
		if position+i < len(nums) {
			jumps := jumpRecursive(nums, position+i)
			if jumps < minJumps {
				minJumps = jumps
			}
		}
	}
	return minJumps + 1
}

func main() {
	nums := []int{2, 3, 1, 1, 4}
	fmt.Println(jump(nums)) // Output: 2
}

